/* Generates frontend/public/supabase-config.js from environment variables.
 *
 * The static marketing pages (public/landing.html, public/auth.html) are plain
 * HTML — Vite never processes them, so they can't read import.meta.env the way
 * the Vue app does. To keep real keys OUT of this (AGPL / open-source) repo, we
 * generate the config at dev/build time from the same VITE_SUPABASE_* vars the
 * SPA uses. The generated file is gitignored; each deployer supplies their own
 * values (Vercel env vars in prod, frontend/.env locally).
 *
 * Runs before `vite` / `vite build` via the npm scripts.
 */
import { writeFileSync, existsSync, readFileSync } from 'node:fs'
import { fileURLToPath } from 'node:url'
import { dirname, resolve } from 'node:path'

const here = dirname(fileURLToPath(import.meta.url))
const root = resolve(here, '..')

// Prefer the real process env (Vercel / CI inject vars here); fall back to
// parsing frontend/.env for local dev.
function loadEnv() {
  const env = { ...process.env }
  const envFile = resolve(root, '.env')
  if (existsSync(envFile)) {
    for (const line of readFileSync(envFile, 'utf8').split('\n')) {
      const m = line.match(/^\s*([\w.-]+)\s*=\s*(.*?)\s*$/)
      if (m && !(m[1] in env)) env[m[1]] = m[2].replace(/^['"]|['"]$/g, '')
    }
  }
  return env
}

const env = loadEnv()
const url = env.VITE_SUPABASE_URL || ''
const key = env.VITE_SUPABASE_PUBLISHABLE_KEY || ''

if (!url || !key) {
  console.warn(
    '[gen-public-config] VITE_SUPABASE_URL / VITE_SUPABASE_PUBLISHABLE_KEY not set — ' +
    'the static landing/auth pages will not be able to sign in until these are configured.'
  )
}

const out = `/* AUTO-GENERATED by scripts/gen-public-config.js — DO NOT EDIT, DO NOT COMMIT.
   Regenerated on every dev/build from the VITE_SUPABASE_* environment vars so the
   static landing/auth pages share the SPA's Supabase config without baking keys
   into the repo. */
export const SUPABASE_URL = ${JSON.stringify(url)};
export const SUPABASE_PUBLISHABLE_KEY = ${JSON.stringify(key)};
`

writeFileSync(resolve(root, 'public', 'supabase-config.js'), out)
console.log('[gen-public-config] wrote public/supabase-config.js')
